solution_code:
#include <iostream>

class Money {
    int m_cents{};
public:
    Money(int cents) : m_cents{cents} {}
    int cents() const { return m_cents; }

    Money& operator+=(const Money& rhs) {
        m_cents += rhs.m_cents;
        return *this;
    }

    Money operator+(const Money& rhs) const {
        return Money{m_cents + rhs.m_cents};
    }
};

int main() {
    int ca, cb;
    std::cin >> ca >> cb;
    Money a{ca}, b{cb};
    Money total = a + b;
    std::cout << "Total: " << total.cents() << "\n";
    return 0;
}

